def require_auth(f):
    """Authentication middleware that validates session tokens."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')
        if not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Authentication required'}), 401

        token = auth_header[7:]
        if not token or len(token) > 200:
            return jsonify({'error': 'Invalid token'}), 401

        token_hash = hash_token(token)
        session = sessions_db.get(token_hash)

        if not session:
            return jsonify({'error': 'Invalid or expired session'}), 401

        if time.time() > session['expires_at']:
            del sessions_db[token_hash]
            return jsonify({'error': 'Session expired'}), 401

        if not session.get('fully_authenticated', False):
            return jsonify({'error': 'MFA verification required'}), 403

        user = users_db.get(session['user_id'])
        if not user:
            return jsonify({'error': 'User not found'}), 401

        g.current_user_id = session['user_id']
        g.current_user = user
        g.session_token_hash = token_hash
        return f(*args, **kwargs)
    return decorated


def create_session(user_id, fully_authenticated=False, pending_mfa=False):
    """Create a new session token."""
    token = generate_secure_token()
    token_hash = hash_token(token)
    sessions_db[token_hash] = {
        'user_id': user_id,
        'fully_authenticated': fully_authenticated,
        'pending_mfa': pending_mfa,
        'created_at': time.time(),
        'expires_at': time.time() + 3600  # 1 hour
    }
    return token


