@app.route('/verify-mfa', methods=['POST'])
def verify_mfa():
    """Verify MFA TOTP code to complete login."""
    data = request.get_json(silent=True)
    if not data:
        return jsonify({'error': 'Invalid request body'}), 400

    auth_header = request.headers.get('Authorization', '')
    if not auth_header.startswith('Bearer '):
        return jsonify({'error': 'Partial session token required'}), 401

    partial_token = auth_header[7:]
    if not partial_token or len(partial_token) > 200:
        return jsonify({'error': 'Invalid token'}), 401

    token_hash = hash_token(partial_token)
    session = sessions_db.get(token_hash)

    if not session or not session.get('pending_mfa'):
        return jsonify({'error': 'Invalid or expired session'}), 401

    if time.time() > session['expires_at']:
        del sessions_db[token_hash]
        return jsonify({'error': 'Session expired'}), 401

    totp_code = data.get('totp_code', '')
    if not validate_totp_code(totp_code):
        return jsonify({'error': 'Invalid TOTP code format'}), 400

    user = users_db.get(session['user_id'])
    if not user:
        # Look up by ID
        user = None
        for u in users_db.values():
            if u['id'] == session['user_id']:
                user = u
                break

    if not user or not user['mfa_secret']:
        return jsonify({'error': 'MFA not configured'}), 400

    totp = pyotp.TOTP(user['mfa_secret'])
    # valid_window=1 allows for slight clock drift (±30 seconds)
    if not totp.verify(totp_code, valid_window=1):
        return jsonify({'error': 'Invalid TOTP code'}), 401

    # Upgrade session to fully authenticated
    del sessions_db[token_hash]
    new_token = create_session(session['user_id'], fully_authenticated=True)

    logger.info("MFA verification successful for user")
    return jsonify({
        'message': 'MFA verification successful',
        'token': new_token
    }), 200


@app.route('/enable-mfa', methods=['POST'])
@require_auth
def enable_mfa():
    """
    Enable MFA for the authenticated user. Returns a TOTP secret
    and provisioning URI. User must confirm setup with a valid code.
    """
    user = g.current_user

    if user['mfa_enabled'] and user['mfa_verified']:
        return jsonify({'error': 'MFA is already enabled'}), 400

    # Generate new TOTP secret
    mfa_secret = pyotp.random_base32()
    user['mfa_secret'] = mfa_secret
    user['mfa_enabled'] = True
    user['mfa_verified'] = False  # Not verified until user confirms

    totp = pyotp.TOTP(mfa_secret)
    provisioning_uri = totp.provisioning_uri(
        name=user['email'],
        issuer_name='SecureApp'
    )

    logger.info("MFA setup initiated for user")
    return jsonify({
        'message': 'MFA setup initiated. Please verify with a TOTP code to complete setup.',
        'secret': mfa_secret,
        'provisioning_uri': provisioning_uri
    }), 200


