@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    """
    Request MFA reset. Sends a secure reset link to the registered email.
    Uses constant-time responses to prevent user enumeration.
    Rate-limited per email address.
    """
    data = request.get_json(silent=True)
    if not data:
        return jsonify({'error': 'Invalid request body'}), 400

    email = data.get('email', '').strip().lower()

    if not validate_email(email):
        return jsonify({'error': 'Invalid email format'}), 400

    # Always return the same response to prevent user enumeration
    generic_response = {
        'message': 'If an account with that email exists and has MFA enabled, a reset link has been sent.'
    }

    user = users_db.get(email)
    if not user:
        # Simulate processing time to prevent timing attacks
        time.sleep(0.1)
        return jsonify(generic_response), 200

    if not user['mfa_enabled']:
        time.sleep(0.1)
        return jsonify(generic_response), 200

    # Rate limiting: prevent abuse
    last_request = user.get('last_mfa_reset_request', 0)
    if time.time() - last_request < app.config['MFA_RESET_RATE_LIMIT_SECONDS']:
        # Still return generic response to prevent enumeration
        return jsonify(generic_response), 200

    # Invalidate any existing reset tokens for this user
    tokens_to_remove = []
    for token_hash, token_data in reset_tokens_db.items():
        if token_data['user_email'] == email:
            tokens_to_remove.append(token_hash)
    for token_hash in tokens_to_remove:
        del reset_tokens_db[token_hash]

    # Generate secure reset token
    reset_token = generate_secure_token()
    token_hash = hash_token(reset_token)

    reset_tokens_db[token_hash] = {
        'user_email': email,
        'created_at': time.time(),
        'expires_at': time.time() + app.config['MFA_RESET_TOKEN_EXPIRY'],
        'used': False
    }

    user['last_mfa_reset_request'] = time.time()

    # Send reset link via email (to the registered email only)
    reset_url = f"{app.config['BASE_URL']}/complete-mfa-reset?token={reset_token}"
    send_email(
        to_email=email,
        subject='MFA Reset Request - SecureApp',
        body=(
            f'You requested to reset your MFA settings.\n\n'
            f'Click the following link to reset your MFA (expires in 15 minutes):\n'
            f'{reset_url}\n\n'
            f'If you did not request this, please secure your account immediately '
            f'and contact support.\n\n'
            f'This link can only be used once.'
        )
    )

    logger.info("MFA reset requested for an account")
    return jsonify(generic_response), 200


@app.route('/complete-mfa-reset', methods=['POST'])
def complete_mfa_reset():
    """
    Complete MFA reset using the token sent via email.
    Requires the reset token AND the account password to prevent
    unauthorized MFA bypass if email is compromised alone.
    """
    data = request.get_json(silent=True)
    if not data:
        return jsonify({'error': 'Invalid request body'}), 400

    token = data.get('token', '')
    password = data.get('password', '')

    if not token or len(token) > 200:
        return jsonify({'error': 'Invalid reset token'}), 400

    if not password:
        return jsonify({'error': 'Password is required to complete MFA reset'}), 400

    token_hash = hash_token(token)
    token_data = reset_tokens_db.get(token_hash)

    if not token_data:
        return jsonify({'error': 'Invalid or expired reset token'}), 400

    if token_data['used']:
        # Token already used - invalidate it completely
        del reset_tokens_db[token_hash]
        return jsonify({'error': 'This reset token has already been used'}), 400

    if time.time() > token_data['expires_at']:
        del reset_tokens_db[token_hash]
        return jsonify({'error': 'Reset token has expired'}), 400

    email = token_data['user_email']
    user = users_db.get(email)

    if not user:
        del reset_tokens_db[token_hash]
        return jsonify({'error': 'Account not found'}), 400

    # Verify password - this ensures that even if email is compromised,
    # attacker still needs the password to disable MFA
    if not verify_password(password, user['password_hash']):
        return jsonify({'error': 'Invalid password'}), 401

    # Mark token as used (single-use)
    token_data['used'] = True

    # Disable MFA
    user['mfa_enabled'] = False
    user['mfa_secret'] = None
    user['mfa_verified'] = False
    user['mfa_reset_pending'] = False

    # Invalidate all existing sessions for this user to force re-login
    sessions_to_remove = []
    for session_hash, session_data in sessions_db.items():
        if session_data['user_id'] == user['id']:
            sessions_to_remove.append(session_hash)
    for session_hash in sessions_to_remove:
        del sessions_db[session_hash]

    # Clean up the used token
    del reset_tokens_db[token_hash]

    # Invalidate any remaining reset tokens for this user
    tokens_to_remove = []
    for th, td in reset_tokens_db.items():
        if td['user_email'] == email:
            tokens_to_remove.append(th)
    for th in tokens_to_remove:
        del reset_tokens_db[th]

    logger.info("MFA reset completed for an account")

    # Notify user that MFA was reset
    send_email(
        to_email=email,
        subject='MFA Has Been Reset - SecureApp',
        body=(
            'Your MFA settings have been reset and MFA has been disabled.\n\n'
            'You can now log in with just your password.\n\n'
            'We strongly recommend re-enabling MFA after logging in.\n\n'
            'If you did not perform this action, please change your password '
            'immediately and contact support.'
        )
    )

    return jsonify({
        'message': 'MFA has been reset. You can now log in with your password. '
                   'Please re-enable MFA for account security.'
    }), 200


