# Cleanup expired tokens periodically (in production, use a background task)
def cleanup_expired_tokens():
    """Remove expired reset tokens and sessions."""
    current_time = time.time()

    expired_tokens = [
        h for h, d in reset_tokens_db.items()
        if current_time > d['expires_at']
    ]
    for h in expired_tokens:
        del reset_tokens_db[h]

    expired_sessions = [
        h for h, d in sessions_db.items()
        if current_time > d['expires_at']
    ]
    for h in expired_sessions:
        del sessions_db[h]


@app.before_request
def before_request():
    """Run cleanup and security checks before each request."""
    cleanup_expired_tokens()

    # Enforce HTTPS in production
    if not request.is_secure and not app.debug:
        return jsonify({'error': 'HTTPS required'}), 403


@app.after_request
def after_request(response):
    """Add security headers to all responses."""
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Strict-Transport-Security'] = 'max-age=31536000; includeSubDomains'
    response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate'
    response.headers['Pragma'] = 'no-cache'
    return response


